package com.company.supervision.api;import com.company.supervision.application.scheduling.NationalWorkdayCalendar;import com.company.supervision.entity.dto.ApiResult;import org.springframework.web.bind.annotation.*;import java.time.LocalDate;@RestController @RequestMapping("/schedules/workday-calendar")public class WorkdayCalendarController{private final NationalWorkdayCalendar c;public WorkdayCalendarController(NationalWorkdayCalendar c){this.c=c;}@GetMapping public ApiResult<?>coverage(){return ApiResult.ok(c.coverage());}@GetMapping("/decision")public ApiResult<?>decision(@RequestParam LocalDate date){return ApiResult.ok(java.util.Map.of("date",date,"decision",c.decision(date),"reason",c.reason(date)));}}
